public static <A, B> ImmutableMultiset<B> transformedCopy(Multiset<A> ms,
      Function<A, B> func) {
    final ImmutableMultiset.Builder<B> ret = ImmutableMultiset.builder();

    for (final Multiset.Entry<A> entry : ms.entrySet()) {
      final B transformedElement = func.apply(entry.getElement());
      ret.addCopies(transformedElement, entry.getCount());
    }

    return ret.build();
  }

public static <A, B> ImmutableMultiset<B> transformedCopy(Multiset<A> ms, Function<A, B> func) {
    ImmutableMultiset.Builder<B> builder = ImmutableMultiset.builder();
    for (Multiset.Entry<A> entry : ms.entrySet()) {
        builder.addCopies(func.apply(entry.getElement()), entry.getCount());
    }
    return builder.build();
}

public static <E, C extends Counter<E>> double saferL2Norm(C c) {
    double maxVal = 0.0;
    for (E key : c.keySet()) {
      double value = Math.abs(c.getCount(key));
      if (value > maxVal)
        maxVal = value;
    }
    double sqrSum = 0.0;
    for (E key : c.keySet()) {
      double count = c.getCount(key);
      sqrSum += Math.pow(count / maxVal, 2);
    }
    return maxVal * Math.sqrt(sqrSum);
  }

public static <E, C extends Counter<E>> double saferL2Norm(C c) {
    double maxVal = 0.0;
    for (E key : c.keySet()) {
        maxVal = Math.max(maxVal, Math.abs(c.getCount(key)));
    }
    if (maxVal == 0.0) {
        return 0.0;
    }
    double sumOfSquares = 0.0;
    for (E key : c.keySet()) {
        double scaled = c.getCount(key) / maxVal;
        sumOfSquares += scaled * scaled;
    }
    return maxVal * Math.sqrt(sumOfSquares);
}

