public static boolean parseDeleteKeyword(final char[] query, int offset) {
    if (query.length < (offset + 6)) {
      return false;
    }

    return (query[offset] | 32) == 'd'
        && (query[offset + 1] | 32) == 'e'
        && (query[offset + 2] | 32) == 'l'
        && (query[offset + 3] | 32) == 'e'
        && (query[offset + 4] | 32) == 't'
        && (query[offset + 5] | 32) == 'e';
  }

public static boolean parseDeleteKeyword(char[] query, int offset) {
    if (query.length < offset + 6) {
        return false;
    }
    String word = new String(query, offset, 6).toLowerCase();
    return word.equals("delete");
}

public static int encodeNum( final long num, final byte[] data, final int beginIndex, final int maxBytes ) {
        for ( int i = 0; i < maxBytes; i++ ) {
            final int pos = maxBytes - i - 1;
            final int idx = beginIndex + pos;
            data[idx] = (byte) ( ( num >> ( 8 * i ) ) & 0xff );
        }
        return beginIndex + maxBytes;
    }

public static int encodeNum(long num, byte[] data, int beginIndex, int maxBytes) {
    for (int i = 0; i < maxBytes; i++) {
        int index = beginIndex + maxBytes - 1 - i;
        data[index] = (byte) ((num >> (8 * i)) & 0xff);
    }
    return beginIndex + maxBytes;
}

